  2→import type { RouteRecordRaw } from 'vue-router'
  3→import { useVault } from '@/composables/useVault'
  4→
  5→const routes: RouteRecordRaw[] = [
  6→  {
  7→    path: '/',
  8→    name: 'welcome',
  9→    component: () => import('@/pages/LandingPage.vue'),
 10→    meta: { requiresAuth: false }
 11→  },
 12→  {
 13→    path: '/app',
 14→    component: () => import('@/layouts/MainLayout.vue'),
 15→    children: [
 16→      {
 17→        path: '',
 18→        name: 'dashboard',
 19→        component: () => import('@/pages/DashboardPage.vue'),
 20→        meta: { requiresAuth: true, requiresOnboarding: true }
 21→      },
 22→      {
 23→        path: 'chat',
 24→        name: 'chat',
 25→        component: () => import('@/pages/ChatPage.vue'),
 26→        meta: { requiresAuth: true, requiresOnboarding: true }
 27→      },
 28→      {
 29→        path: 'activities',
 30→        name: 'activities',
 31→        component: () => import('@/pages/ActivitiesPage.vue'),
 32→        meta: { requiresAuth: true, requiresOnboarding: true }
 33→      },
 34→      {
 35→        path: 'metrics',
 36→        name: 'metrics',
 37→        component: () => import('@/pages/MetricsPage.vue'),
 38→        meta: { requiresAuth: true, requiresOnboarding: true }
 39→      },
 40→      {
 41→        path: 'journal',
 42→        name: 'journal',
 43→        component: () => import('@/pages/JournalPage.vue'),
 44→        meta: { requiresAuth: true, requiresOnboarding: true }
 45→      },
 46→      {
 47→        path: 'network',
 48→        name: 'network',
 49→        component: () => import('@/pages/NetworkPage.vue'),
 50→        meta: { requiresAuth: true, requiresOnboarding: true }
 51→      },
 52→      {
 53→        path: 'settings',
 54→        name: 'settings',
 55→        component: () => import('@/pages/SettingsPage.vue'),
 56→        meta: { requiresAuth: true }
 57→      }
 58→    ]
 59→  },
 60→  {
 61→    path: '/onboarding',
 62→    name: 'onboarding',
 63→    component: () => import('@/pages/OnboardingPage.vue'),
 64→    meta: { requiresAuth: true }
 65→  },
 66→  {
 67→    path: '/unlock',
 68→    name: 'unlock',
 69→    component: () => import('@/pages/UnlockPage.vue')
 70→  },
 71→  {
 72→    path: '/setup',
 73→    name: 'setup',
 74→    component: () => import('@/pages/SetupPage.vue')
 75→  },
 76→  {
 77→    path: '/setup/recovery-phrase',
 78→    name: 'setup-recovery-phrase',
 79→    component: () => import('@/pages/RecoveryPhraseSetupPage.vue'),
 80→    meta: { requiresAuth: true }
 81→  },
 82→  {
 83→    path: '/recovery',
 84→    name: 'recovery',
 85→    component: () => import('@/pages/RecoveryPage.vue')
 86→  }
 87→]
 88→
 89→const router = createRouter({
 90→  history: createWebHistory(),
 91→  routes
 92→})
 93→
 94→// Navigation guards
 95→router.beforeEach(async (to, _from, next) => {
 96→  const { isUnlocked, needsSetup, getProfile } = useVault()
 97→
 98→  // If vault is locked and route requires auth, redirect to unlock (which handles both new and returning users)
 99→  if (to.meta.requiresAuth && !isUnlocked.value) {
100→    return next({ name: 'unlock' })
101→  }
102→
103→  // If route requires onboarding, check if user has completed it
104→  if (to.meta.requiresOnboarding && isUnlocked.value) {
105→    const profile = await getProfile()
106→    if (!profile?.onboardingComplete) {
107→      return next({ name: 'onboarding' })
108→    }
109→  }
110→
111→  // If user is unlocked and tries to go to unlock/setup/recovery/welcome, redirect appropriately
112→  if (isUnlocked.value && (to.name === 'unlock' || to.name === 'setup' || to.name === 'recovery' || to.name === 'welcome')) {
113→    // Check if user has completed onboarding
114→    const profile = await getProfile()
115→    if (!profile?.onboardingComplete) {
116→      // Allow setup-recovery-phrase page during onboarding flow
117→      return next({ name: 'onboarding' })
118→    }
119→    return next({ name: 'dashboard' })
120→  }
121→
122→  // If user hasn't set up vault and tries to go somewhere other than unlock/setup/setup-recovery-phrase/recovery/welcome, redirect to unlock
