 14→export function useAutoLock() {
 15→  const router = useRouter()
 16→  const { lock, isUnlocked, getAppSettings } = useVault()
 17→
 18→  const updateActivity = () => {
 19→    lastActivityTime.value = Date.now()
 20→  }
 21→
 22→  const checkInactivity = () => {
 23→    // Don't check if auto-lock is disabled (0 minutes) or vault is already locked
 24→    if (autoLockMinutes.value === 0 || !isUnlocked.value) {
 25→      return
 26→    }
 27→
 28→    const inactiveMs = Date.now() - lastActivityTime.value
 29→    const thresholdMs = autoLockMinutes.value * 60 * 1000
 30→
 31→    if (inactiveMs >= thresholdMs) {
 32→      lock()
 33→      router.push({ name: 'unlock' })
 34→    }
 35→  }
 36→
 37→  const loadSettings = async () => {
 38→    try {
 39→      const settings = await getAppSettings()
 40→      autoLockMinutes.value = settings.autoLockMinutes
 41→    } catch {
 42→      // Use default if settings can't be loaded
 43→      autoLockMinutes.value = 5
 44→    }
 45→  }
 46→
 47→  const initialize = () => {
 48→    if (isInitialized) return
 49→
 50→    // Add activity listeners
 51→    ACTIVITY_EVENTS.forEach(event => {
 52→      document.addEventListener(event, updateActivity, { passive: true })
 53→    })
 54→
 55→    // Start checking for inactivity
 56→    checkInterval = setInterval(checkInactivity, CHECK_INTERVAL_MS)
 57→    isInitialized = true
 58→  }
 59→
 60→  const cleanup = () => {
 61→    if (!isInitialized) return
 62→
 63→    // Remove activity listeners
 64→    ACTIVITY_EVENTS.forEach(event => {
 65→      document.removeEventListener(event, updateActivity)
 66→    })
 67→
 68→    // Stop checking
 69→    if (checkInterval) {
 70→      clearInterval(checkInterval)
